class GalleryManager{constructor(i={}){this.options=Object.assign({lightboxSelector:".glightbox",sliderSelector:"#thumbnail-slider",mainImageClass:".gallery-main-item",splideConfig:{fixedWidth:100,fixedHeight:65,gap:10,rewind:!0,pagination:!1,isNavigation:!0,arrows:!0,breakpoints:{600:{fixedWidth:60,fixedHeight:44}}}},i),this.initLightbox(),this.initSlider()}initLightbox(){"undefined"!=typeof GLightbox?this.lightbox=GLightbox({selector:this.options.lightboxSelector}):console.warn("GalleryManager: GLightbox n'est pas chargé.")}initSlider(){document.querySelector(this.options.sliderSelector)&&"undefined"!=typeof Splide&&(this.splide=new Splide(this.options.sliderSelector,this.options.splideConfig).mount(),this.syncMainImages())}syncMainImages(){const i=document.querySelectorAll(this.options.mainImageClass);this.splide&&i.length>0&&this.splide.on("active",(e=>{i.forEach((i=>i.classList.remove("is-active")));const t=document.getElementById(`main-image-${e.index}`);t&&t.classList.add("is-active")}))}}